import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from "https://esm.sh/@supabase/supabase-js@2";
import Stripe from "https://esm.sh/stripe@12.0.0?target=deno";
import { checkRateLimit } from "../_shared/rate-limiter.ts";
import { getCorsHeaders, handleCorsPreFlight } from "../_shared/cors.ts";

serve(async (req) => {
  const preflightResponse = handleCorsPreFlight(req);
  if (preflightResponse) return preflightResponse;

  const corsHeaders = getCorsHeaders(req);

  // Rate limiting
  const { allowed, response: rateLimitResponse } = await checkRateLimit(req, 'payment');
  if (!allowed) {
    return rateLimitResponse!;
  }

  try {
    const stripe = new Stripe(Deno.env.get("STRIPE_SECRET_KEY") || "", {
      apiVersion: "2023-10-16",
    });

    const supabase = createClient(
      Deno.env.get("SUPABASE_URL") || "",
      Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") || ""
    );

    const body = await req.json();
    const {
      eventId,
      tableId,
      tableNumber,
      tableTier,
      tablePrice,
      tableCapacity,
      bottlesIncluded,
      customerEmail,
      customerName,
      customerPhone,
      guestCount,
      celebration,
      celebrantName,
      specialRequests,
      bottlePreferences,
      estimatedArrival,
      // Host entry ticket (REQUIRED for unified checkout)
      ticketTierId,
      ticketTierName,
      ticketPriceCents,
      // Guest tickets (OPTIONAL — host can buy for guests)
      gaTicketCount,
      gaTicketTypeId,
      gaTicketPrice,
    } = body;

    console.log("Creating unified VIP payment intent for:", { eventId, tableId, customerEmail, tablePrice, ticketTierId });

    // Validate required fields (including GA ticket for unified checkout)
    // Note: tablePrice and ticketPriceCents are intentionally NOT required from the client.
    // Prices are fetched server-side from the database to prevent price tampering.
    if (!eventId || !tableId || !customerEmail || !customerName || !ticketTierId) {
      return new Response(
        JSON.stringify({ error: "Missing required fields. VIP checkout requires GA ticket selection." }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 400 },
      );
    }

    // Verify event exists
    const { data: event, error: eventError } = await supabase
      .from("events")
      .select("id, name")
      .eq("id", eventId)
      .single();

    if (eventError || !event) {
      console.error("Event lookup error:", eventError);
      return new Response(
        JSON.stringify({ error: "Event not found" }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 404 },
      );
    }

    // Verify table exists and is available
    const { data: table, error: tableError } = await supabase
      .from("event_vip_tables")
      .select("*")
      .eq("id", tableId)
      .single();

    if (tableError || !table) {
      console.error("Table lookup error:", tableError);
      return new Response(
        JSON.stringify({ error: "Table not found" }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 404 },
      );
    }

    if (!table.is_available) {
      return new Response(
        JSON.stringify({ error: "Table is no longer available" }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 400 },
      );
    }

    // Fetch GA ticket price from database (never trust client-sent prices)
    const { data: ticketType, error: ticketTypeError } = await supabase
      .from("ticket_types")
      .select("id, name, price, fee")
      .eq("id", ticketTierId)
      .single();

    if (ticketTypeError || !ticketType) {
      console.error("Ticket type lookup error:", ticketTypeError);
      return new Response(
        JSON.stringify({ error: "Ticket type not found" }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 404 },
      );
    }

    // Calculate prices from DATABASE values, not client input
    // The event_vip_tables column is price_cents, not price
    const vipTablePriceCents = table.price_cents != null ? table.price_cents : Math.round(Number(tablePrice) * 100);
    const serverTicketPriceCents = Math.round((ticketType.price + (ticketType.fee || 0)) * 100);

    // Guest tickets: validate count against table capacity, use same server-side price
    const validatedGuestCount = Math.min(
      Math.max(0, parseInt(gaTicketCount) || 0),
      (table.capacity || 6) - 1  // Cap at capacity minus host
    );
    const guestTicketsCents = validatedGuestCount * serverTicketPriceCents;

    const totalAmountCents = vipTablePriceCents + serverTicketPriceCents + guestTicketsCents;

    // Build package snapshot with booking details (using server-side prices)
    const packageSnapshot = {
      tier: table.tier || tableTier,
      capacity: table.capacity,
      bottlesIncluded: table.bottles_included || bottlesIncluded,
      guestCount: guestCount || table.capacity,
      celebration: celebration || null,
      celebrantName: celebrantName || null,
      bottlePreferences: bottlePreferences || null,
      estimatedArrival: estimatedArrival || null,
      priceAtBooking: vipTablePriceCents / 100,
      // Host entry ticket - prices from DB
      ticketTierId: ticketTierId,
      ticketTierName: ticketType.name || ticketTierName || "General Admission",
      ticketPrice: serverTicketPriceCents / 100,
      // Guest tickets purchased by host
      guestTicketCount: validatedGuestCount,
      guestTicketTotalCents: guestTicketsCents,
      totalAmount: totalAmountCents / 100,
    };

    // Create unified VIP checkout (GA ticket + VIP reservation) atomically via RPC
    // This creates both the GA ticket and VIP reservation in a single transaction
    const { data: checkoutResult, error: checkoutError } = await supabase
      .rpc("create_unified_vip_checkout", {
        p_event_id: eventId,
        p_table_id: tableId,
        p_table_number: parseInt(tableNumber),
        p_tier_id: ticketTierId,
        p_tier_name: ticketType.name || ticketTierName || "General Admission",
        p_tier_price_cents: serverTicketPriceCents,
        p_vip_price_cents: vipTablePriceCents,
        p_total_amount_cents: totalAmountCents,
        p_purchaser_name: customerName,
        p_purchaser_email: customerEmail,
        p_purchaser_phone: customerPhone || null,
        p_stripe_payment_intent_id: "", // Will be updated after payment intent creation
        p_package_snapshot: packageSnapshot,
        p_special_requests: specialRequests || null,
      })
      .single();

    if (checkoutError || !checkoutResult) {
      console.error("Unified checkout creation error:", checkoutError);
      return new Response(
        JSON.stringify({ error: `Failed to create unified checkout: ${checkoutError?.message || "Unknown error"}` }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 500 },
      );
    }

    const { ticket_id, reservation_id, unified_qr_token, ticket_token } = checkoutResult;
    console.log("Unified checkout created:", { ticket_id, reservation_id, unified_qr_token });

    // Create Stripe Payment Intent for combined amount (VIP table + GA ticket)
    let paymentIntent;
    try {
      paymentIntent = await stripe.paymentIntents.create({
        amount: totalAmountCents,
        currency: "usd",
        automatic_payment_methods: {
          enabled: true,
        },
        metadata: {
          type: "vip_unified",
          reservationId: reservation_id,
          ticketId: ticket_id,
          eventId,
          tableId,
          tableNumber,
          tableTier: table.tier || tableTier || "standard",
          ticketTierId,
          ticketTierName: ticketType.name || ticketTierName || "General Admission",
          customerEmail,
          customerName,
          vipPriceCents: String(vipTablePriceCents),
          ticketPriceCents: String(serverTicketPriceCents),
          totalAmountCents: String(totalAmountCents),
          // Guest ticket metadata for webhook processing
          gaTicketCount: String(validatedGuestCount),
          gaTicketTypeId: ticketTierId,
          gaTicketPrice: String(serverTicketPriceCents / 100),
          tableCapacity: String(table.capacity || 6),
        },
        receipt_email: customerEmail,
        description: `VIP Table ${table.table_number || tableNumber} (${(table.tier || tableTier || "standard").replace('_', ' ')}) + ${1 + validatedGuestCount} GA Ticket${validatedGuestCount > 0 ? 's' : ''} for ${event.name}`,
      });
    } catch (stripeError) {
      console.error("Stripe payment intent creation failed:", stripeError);
      // Transactional rollback: cancel reservation, ticket, and restore table atomically
      const { error: rollbackError } = await supabase.rpc("rollback_vip_checkout", {
        p_reservation_id: reservation_id,
        p_ticket_id: ticket_id,
        p_table_id: tableId,
      });
      if (rollbackError) {
        console.error("VIP rollback failed:", rollbackError);
      }

      return new Response(
        JSON.stringify({ error: "Failed to create payment intent. Please try again." }),
        { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 500 },
      );
    }

    // Update reservation and ticket with payment intent ID
    await Promise.all([
      supabase
        .from("vip_reservations")
        .update({ stripe_payment_intent_id: paymentIntent.id })
        .eq("id", reservation_id),
      supabase
        .from("tickets")
        .update({ stripe_payment_intent_id: paymentIntent.id })
        .eq("id", ticket_id),
    ]);

    console.log("Payment Intent created:", paymentIntent.id);

    return new Response(
      JSON.stringify({
        clientSecret: paymentIntent.client_secret,
        paymentIntentId: paymentIntent.id,
        reservationId: reservation_id,
        ticketId: ticket_id,
        unifiedQrToken: unified_qr_token,
        amount: totalAmountCents / 100,
        vipAmount: vipTablePriceCents / 100,
        ticketAmount: serverTicketPriceCents / 100,
        guestTicketCount: validatedGuestCount,
        guestTicketAmount: guestTicketsCents / 100,
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 200 },
    );
  } catch (error) {
    console.error("VIP Payment Intent error:", error);
    return new Response(
      JSON.stringify({ error: error instanceof Error ? error.message : "Unknown error" }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" }, status: 500 },
    );
  }
});

/**
 * Rate Limiter Shared Module
 * Uses Upstash Redis for distributed rate limiting across edge function instances
 *
 * Tiered limits:
 * - auth: 20 requests per minute per IP
 * - payment: 20 requests per minute per IP
 * - read: 200 requests per minute per IP
 * - webhook: exempt (no rate limiting)
 */

import { Ratelimit } from "https://esm.sh/@upstash/ratelimit@latest";
import { Redis } from "https://esm.sh/@upstash/redis@latest";

export type EndpointType = 'auth' | 'payment' | 'read' | 'webhook';

// Lazy-initialized Redis client factory
function createRedis(): Redis {
  return new Redis({
    url: Deno.env.get("UPSTASH_REDIS_REST_URL")!,
    token: Deno.env.get("UPSTASH_REDIS_REST_TOKEN")!,
  });
}

// Cache limiters to avoid recreating on each request
let authLimiter: Ratelimit | null = null;
let paymentLimiter: Ratelimit | null = null;
let readLimiter: Ratelimit | null = null;

function getLimiter(type: EndpointType): Ratelimit | null {
  // Webhooks are exempt from rate limiting
  if (type === 'webhook') return null;

  const redis = createRedis();

  switch (type) {
    case 'auth':
      if (!authLimiter) {
        authLimiter = new Ratelimit({
          redis,
          limiter: Ratelimit.slidingWindow(20, "60 s"),
          prefix: "maguey:auth",
        });
      }
      return authLimiter;
    case 'payment':
      if (!paymentLimiter) {
        paymentLimiter = new Ratelimit({
          redis,
          limiter: Ratelimit.slidingWindow(20, "60 s"),
          prefix: "maguey:payment",
        });
      }
      return paymentLimiter;
    case 'read':
      if (!readLimiter) {
        readLimiter = new Ratelimit({
          redis,
          limiter: Ratelimit.slidingWindow(200, "60 s"),
          prefix: "maguey:read",
        });
      }
      return readLimiter;
    default:
      return null;
  }
}

/**
 * Check rate limit for a request
 *
 * @param req - The incoming request
 * @param endpointType - Type of endpoint (auth, payment, read, webhook)
 * @returns Object with allowed boolean and optional response if blocked
 *
 * @example
 * ```typescript
 * const { allowed, response } = await checkRateLimit(req, 'payment');
 * if (!allowed) {
 *   return response!;
 * }
 * // Continue with request processing...
 * ```
 */
export async function checkRateLimit(
  req: Request,
  endpointType: EndpointType
): Promise<{ allowed: boolean; response?: Response }> {
  // Webhooks are exempt from rate limiting
  if (endpointType === 'webhook') {
    return { allowed: true };
  }

  // Skip rate limiting if Upstash is not configured (fail-open pattern)
  const upstashUrl = Deno.env.get("UPSTASH_REDIS_REST_URL");
  if (!upstashUrl) {
    console.log("[rate-limiter] Upstash not configured, skipping rate limit");
    return { allowed: true };
  }

  const limiter = getLimiter(endpointType);
  if (!limiter) {
    return { allowed: true };
  }

  // Get client IP from headers (Supabase sets x-forwarded-for)
  const clientIP = req.headers.get("x-forwarded-for")?.split(",")[0]?.trim()
    || req.headers.get("x-real-ip")
    || "unknown";

  try {
    const { success, remaining, reset } = await limiter.limit(clientIP);

    if (!success) {
      const retryAfter = Math.ceil((reset - Date.now()) / 1000);
      console.log(`[rate-limiter] Rate limit exceeded for ${clientIP} on ${endpointType} endpoint`);

      return {
        allowed: false,
        response: new Response(
          JSON.stringify({
            error: "Rate limit exceeded",
            retryAfter,
          }),
          {
            status: 429,
            headers: {
              "Content-Type": "application/json",
              "Retry-After": retryAfter.toString(),
              "X-RateLimit-Remaining": remaining.toString(),
              "X-RateLimit-Reset": reset.toString(),
            },
          }
        ),
      };
    }

    return { allowed: true };
  } catch (error) {
    // Fail open - don't block requests if rate limiting fails
    console.error("[rate-limiter] Error checking rate limit:", error);
    return { allowed: true };
  }
}

/**
 * Shared CORS configuration for Edge Functions
 *
 * Override with ALLOWED_ORIGINS env var (comma-separated) if needed.
 * When ALLOWED_ORIGINS is not set, production domains are used as default.
 * For local dev, set ALLOWED_ORIGINS=* to allow all origins.
 */

const PRODUCTION_ORIGINS = [
  "https://tickets.magueynightclub.com",
  "https://staff.magueynightclub.com",
  "https://magueynightclub.com",
  "https://www.magueynightclub.com",
];

const DEV_ORIGINS = [
  "http://localhost:3015",
  "http://localhost:3016",
  "http://localhost:3017",
];

export function getAllowedOrigin(requestOrigin: string | null): string {
  const allowedOriginsEnv = Deno.env.get("ALLOWED_ORIGINS");

  // If env var is explicitly set, use it (set ALLOWED_ORIGINS=* for dev)
  if (allowedOriginsEnv) {
    if (allowedOriginsEnv.trim() === "*") {
      return "*";
    }
    const allowedOrigins = allowedOriginsEnv.split(",").map((o) => o.trim());
    if (requestOrigin && allowedOrigins.includes(requestOrigin)) {
      return requestOrigin;
    }
    return allowedOrigins[0] || PRODUCTION_ORIGINS[0];
  }

  // Default: production origins + localhost for development
  if (requestOrigin && PRODUCTION_ORIGINS.includes(requestOrigin)) {
    return requestOrigin;
  }
  if (requestOrigin && DEV_ORIGINS.includes(requestOrigin)) {
    return requestOrigin;
  }
  return PRODUCTION_ORIGINS[0];
}

/**
 * Get CORS headers for a request, using dynamic origin checking.
 * @param req The incoming request (used for origin matching)
 * @param extraAllowedHeaders Optional additional headers to allow (comma-separated string)
 */
export function getCorsHeaders(req: Request, extraAllowedHeaders?: string) {
  const baseHeaders = "authorization, x-client-info, apikey, content-type";
  const allowHeaders = extraAllowedHeaders
    ? `${baseHeaders}, ${extraAllowedHeaders}`
    : baseHeaders;

  return {
    "Access-Control-Allow-Origin": getAllowedOrigin(req.headers.get("origin")),
    "Access-Control-Allow-Headers": allowHeaders,
    "Access-Control-Allow-Methods": "POST, GET, OPTIONS, PUT, DELETE",
  };
}

/**
 * Handle CORS preflight (OPTIONS) request.
 * Returns a Response if this is a preflight, or null if it should be handled normally.
 * @param req The incoming request
 * @param extraAllowedHeaders Optional additional headers to allow
 */
export function handleCorsPreFlight(req: Request, extraAllowedHeaders?: string): Response | null {
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: getCorsHeaders(req, extraAllowedHeaders) });
  }
  return null;
}
